		"small", "span", "strong", "sub", "sup", "time", "u", "var", "wbr",
	)
	p.AllowStandardAttributes()
	p.AllowStyling()
	p.AllowImages()
	p.AllowAttrs("cite").OnElements("del", "ins", "q")
	p.AllowAttrs("datetime").OnElements("del", "ins", "time")
	p.AllowAttrs("value").OnElements("data")
	return p
}

var whiteSpaceRe = regexp.MustCompile(`\s+`)

// sanitizeTOCHeadingTitle sanitizes s for use as a TOC heading title.
func sanitizeTOCHeadingTitle(s string) string {
	if strings.IndexByte(s, '<') == -1 {
		return s
	}

	// Sanitize the string.
	ss := tocSanitizerPolicy.Sanitize(s)

	// Remove extraneous whitespace.
	return whiteSpaceRe.ReplaceAllString(strings.TrimSpace(ss), " ")
}

type tocPassthroughRenderer struct{}

func (r *tocPassthroughRenderer) RegisterFuncs(reg renderer.NodeRendererFuncRegisterer) {
	reg.Register(passthroughAst.KindPassthroughInline, r.renderPassthroughInline)
	reg.Register(passthroughAst.KindPassthroughBlock, r.renderPassthroughBlock)
}

func (r *tocPassthroughRenderer) renderPassthroughInline(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
	if !entering {
		return ast.WalkContinue, nil
	}
	pn, ok := n.(*passthroughAst.PassthroughInline)
	if !ok {
		return ast.WalkContinue, nil
	}
	w.Write(pn.Segment.Value(source))
	return ast.WalkContinue, nil
}

func (r *tocPassthroughRenderer) renderPassthroughBlock(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
	if !entering {
		return ast.WalkContinue, nil
	}
	pn, ok := n.(*passthroughAst.PassthroughBlock)
	if !ok {
		return ast.WalkContinue, nil
	}
	l := pn.Lines().Len()
	for i := 0; i < l; i++ {
		line := pn.Lines().At(i)
		w.Write(line.Value(source))
	}
	return ast.WalkContinue, nil
}

